pub fn collect_values(root: &serde_json::Value, pointer: &[String], property_name: &str) -> Vec<ValueSuggestion> {
    let mut full_pointer: Vec<String> = pointer.to_vec();
    full_pointer.push(property_name.to_string());

    let Some(subschema) = resolve_subschema_at_pointer(root, &full_pointer) else {
        return vec![];
    };

    let mut suggestions = Vec::new();
    let mut seen = HashSet::new();
    collect_values_from(root, subschema, &mut suggestions, &mut seen, 0);
    suggestions
}

fn collect_values_from(root: &serde_json::Value, schema: &serde_json::Value, suggestions: &mut Vec<ValueSuggestion>, seen: &mut HashSet<ValueSuggestionKey>, depth: usize) {
    if depth > MAX_SCHEMA_DEPTH { return; }
    let mut visited = HashSet::new();
    let Some(schema) = follow_ref(root, schema, &mut visited) else { return; };

    // Const is definitive.
    if let Some(const_val) = schema.get("const") {
        if seen.insert(ValueSuggestionKey::Const(const_val.clone())) {
            suggestions.push(ValueSuggestion::Const(const_val.clone()));
        }
        return;
    }

    // Enum is definitive.
    if let Some(enum_vals) = schema.get("enum").and_then(|v| v.as_array()) {
        for val in enum_vals {
            if seen.insert(ValueSuggestionKey::Enum(val.clone())) {
                suggestions.push(ValueSuggestion::Enum(val.clone()));
            }
        }
        return;
    }

    // Type-based suggestions.
    if let Some(type_val) = schema.get("type") {
        if let Some(type_str) = type_val.as_str() {
            match type_str {
                "boolean" => push_boolean(suggestions, seen),
                "null" => push_null(suggestions, seen),
                _ => {}
            }
        } else if let Some(type_arr) = type_val.as_array() {
            let mut has_boolean = false;
            let mut has_null = false;
            for t in type_arr.iter().filter_map(|v| v.as_str()) {
                match t {
                    "boolean" => has_boolean = true,
                    "null" => has_null = true,
                    _ => {}
                }
            }
            if has_boolean { push_boolean(suggestions, seen); }
            if has_null { push_null(suggestions, seen); }
        }
    }

    // Composition branches.
    for key in ["allOf", "anyOf", "oneOf"] {
        if let Some(branches) = schema.get(key).and_then(|v| v.as_array()) {
            for branch in branches {
                collect_values_from(root, branch, suggestions, seen, depth + 1);
            }
        }
    }
}

#[derive(Hash, Eq, PartialEq, Clone)]
enum ValueSuggestionKey {
    Const(serde_json::Value),
    Enum(serde_json::Value),
    Boolean,
    Null,
}

fn push_boolean(suggestions: &mut Vec<ValueSuggestion>, seen: &mut HashSet<ValueSuggestionKey>) {
    if seen.insert(ValueSuggestionKey::Boolean) {
        suggestions.push(ValueSuggestion::Boolean);
    }
}

fn push_null(suggestions: &mut Vec<ValueSuggestion>, seen: &mut HashSet<ValueSuggestionKey>) {
    if seen.insert(ValueSuggestionKey::Null) {
        suggestions.push(ValueSuggestion::Null);
    }
}
