/// Determine the effective JSON Schema type for a property schema, handling
/// `$ref`, type arrays, and `allOf`/`anyOf`/`oneOf` branches.
///
/// For type arrays, the first non-null type is preferred. For composed schemas,
/// the first non-null type found among the branches is returned. Returns `None`
/// if no type can be determined.
fn effective_schema_type(root: &serde_json::Value, schema: &serde_json::Value) -> Option<String> {
    let mut visited = HashSet::new();
    effective_schema_type_inner(root, schema, &mut visited, 0)
}

fn effective_schema_type_inner(
    root: &serde_json::Value,
    schema: &serde_json::Value,
    visited: &mut HashSet<String>,
    depth: usize,
) -> Option<String> {
    if depth > MAX_SCHEMA_DEPTH {
        return None;
    }

    let schema = follow_ref(root, schema, visited)?;

    // First pass: composition branches, preferring non-null types.
    for key in ["allOf", "anyOf", "oneOf"] {
        if let Some(branches) = schema.get(key).and_then(|v| v.as_array()) {
            for branch in branches {
                if let Some(t) = effective_schema_type_inner(root, branch, visited, depth + 1) {
                    if t != "null" {
                        return Some(t);
                    }
                }
            }
        }
    }

    // Immediate type field.
    if let Some(type_val) = schema.get("type") {
        if let Some(s) = type_val.as_str() {
            return Some(s.to_string());
        }
        if let Some(arr) = type_val.as_array() {
            let first_non_null = arr
                .iter()
                .filter_map(|v| v.as_str())
                .find(|t| *t != "null")
                .map(|t| t.to_string());
            if first_non_null.is_some() {
                return first_non_null;
            }
            if arr.iter().any(|v| v.as_str() == Some("null")) {
                return Some("null".to_string());
            }
        }
    }

    // Fallback: accept null from branches if no non-null type was found.
    for key in ["allOf", "anyOf", "oneOf"] {
        if let Some(branches) = schema.get(key).and_then(|v| v.as_array()) {
            for branch in branches {
                if let Some(t) = effective_schema_type_inner(root, branch, visited, depth + 1) {
                    return Some(t);
                }
            }
        }
    }

    None
}

