/// Composed schemas do not produce duplicate property suggestions.
#[tokio::test]
async fn completion_composition_no_duplicate_properties() {
    let mut client = TestClient::new();
    client.initialize().await;

    // allOfObject appears in both branches of the top-level schema? No, we need a
    // property that appears in multiple branches. Use allOfObject which merges
    // two branches; name does not appear in both branches, but we can test the
    // allOfObject property itself only appears once at the root.
    let content = composition_doc_with_schema("");
    let uri = composition_doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let cursor_col = (content.len() - 1) as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let items = result["items"].as_array().unwrap();
    let mut seen = std::collections::HashSet::new();
    for item in items {
        let label = item["label"].as_str().unwrap();
        assert!(
            seen.insert(label.to_string()),
            "duplicate property suggestion: {label}"
        );
    }
}

/// Composed value schemas do not produce duplicate value suggestions.
#[tokio::test]
async fn completion_composition_no_duplicate_values() {
    let mut client = TestClient::new();
    client.initialize().await;

    // oneOfValue branches both include "beta" indirectly (second branch), and
    // the first branch has "stable". No overlap in our fixture, so extend the
    // document with a property that has overlapping enum values.
    let schema = composition_schema_path();
    let content = format!(
        r#"{{"$schema": "{schema}", "overlap": null}}"#,
    );
    // Use a custom schema inline to test overlap without adding a new fixture.
    let custom_schema = r#"{
        "type": "object",
        "properties": {
            "overlap": {
                "anyOf": [
                    { "enum": ["a", "b"] },
                    { "enum": ["b", "c"] }
                ]
            }
        }
    }"#;
    let dir = std::path::Path::new(&env!("CARGO_MANIFEST_DIR")).join("tests/fixtures");
    let custom_schema_path = dir.join("completion-overlap-schema.json");
    std::fs::write(&custom_schema_path, custom_schema).unwrap();
    let content = format!(
        r#"{{"$schema": "{}", "overlap": null}}"#,
        custom_schema_path.display()
    );
    let uri = composition_doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let idx = content.find("\"overlap\": ").unwrap() + "\"overlap\": ".len();
    let result = client.completion(&uri, 0, idx as u32).await;

    let names = labels(&result);
    assert_eq!(
        names.len(),
        3,
        "expected exactly 3 unique values (a, b, c), got: {names:?}"
    );
    assert!(names.contains(&"\"a\"".to_string()));
    assert!(names.contains(&"\"b\"".to_string()));
    assert!(names.contains(&"\"c\"".to_string()));
}

